import pytest
import requests

def test_update_timesheet_hours_at_minimum_boundary_returns_success(
    hr_admin_token,
    existing_timesheet_id,
    api_base_url,
):
    headers = {"Authorization": f"Bearer {hr_admin_token}", "Content-Type": "application/json"}
    base_payload = {
        "employee_id": "EMP-001",
        "period_start": "2024-01-01",
        "period_end": "2024-01-07",
        "status": "submitted"
    }
    url = f"{api_base_url}/api/timesheets/{existing_timesheet_id}"

    valid_payload = {**base_payload, "hours_worked": 0}
    r_valid = requests.put(url, json=valid_payload, headers=headers)
    assert r_valid.status_code in (200, 201), f"Expected 200/201 for hours=0, got {r_valid.status_code}"

    invalid_payload = {**base_payload, "hours_worked": -1}
    r_invalid = requests.put(url, json=invalid_payload, headers=headers)
    assert r_invalid.status_code == 400, f"Expected 400 for hours=-1, got {r_invalid.status_code}"
